1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import {
5	  Dialog,
6	  DialogContent,
7	  DialogTitle,
8	} from "@/components/ui/dialog";
9	import { Printer, Send, CheckCircle2, Clock, AlertCircle, Maximize2, Minimize2, Download, Lock, Palette, X } from "lucide-react";
10	import { useDownloadPDF } from "@/hooks/use-download-pdf";
11	import { useSubscription } from "@/hooks/use-subscription";
12	import { SendDocumentDialog } from "@/components/studio/SendDocumentDialog";
13	import { format } from "date-fns";
14	import { toast } from "sonner";
15	import { cn } from "@/lib/utils";
16	
17	const INVOICE_THEMES = [
18	  { name: "Crevia Gold",  hex: "#B07D3A", pro: false },
19	  { name: "Noir",         hex: "#18181B", pro: true  },
20	  { name: "Cobalt",       hex: "#1E40AF", pro: true  },
21	  { name: "Emerald",      hex: "#065F46", pro: true  },
22	  { name: "Amethyst",     hex: "#5B21B6", pro: true  },
23	  { name: "Crimson",      hex: "#991B1B", pro: true  },
24	  { name: "Slate",        hex: "#1E293B", pro: true  },
25	  { name: "Copper",       hex: "#92400E", pro: true  },
26	  { name: "Rose",         hex: "#9D174D", pro: true  },
27	  { name: "Teal",         hex: "#0F4C5C", pro: true  },
28	  { name: "Graphite",     hex: "#374151", pro: true  },
29	  { name: "Midnight",     hex: "#0C1445", pro: true  },
30	] as const;
31	
32	const DEFAULT_COLOR = "#B07D3A";
33	
34	interface InvoiceItem {
35	  id: string;
36	  description: string;
37	  quantity: number;
38	  unit_price: number;
39	  total: number;
40	}
41	
42	interface InvoicePreviewDialogProps {
43	  open: boolean;
44	  onOpenChange: (open: boolean) => void;
45	  invoice: any;
46	}
47	
48	const InvoicePreviewDialog = ({ open, onOpenChange, invoice }: InvoicePreviewDialogProps) => {
49	  const [items, setItems]                       = useState<InvoiceItem[]>([]);
50	  const [profile, setProfile]                   = useState<any>(null);
51	  const [businessSettings, setBusinessSettings] = useState<any>(null);
52	  const [isFullscreen, setIsFullscreen]         = useState(false);
53	  const [showSendDialog, setShowSendDialog]     = useState(false);
54	  const [accentColor, setAccentColor]           = useState(DEFAULT_COLOR);
55	  const [savingColor, setSavingColor]           = useState(false);
56	  const [showPalette, setShowPalette]           = useState(false);
57	
58	  const { isPro, isBrandWorkspace, isBusiness } = useSubscription();
59	  const isProUser = isPro || isBrandWorkspace || isBusiness;
60	
61	  const { ref: docRef, download, downloading } = useDownloadPDF(
62	    invoice ? `Invoice-${invoice.invoice_number}` : "Invoice"
63	  );
64	
65	  useEffect(() => {
66	    if (!invoice) return;
67	    setAccentColor(invoice.accent_color || DEFAULT_COLOR);
68	    fetchItems();
69	    fetchProfile();
70	    fetchBusinessSettings();
71	  }, [invoice]);
72	
73	  const fetchItems = async () => {
74	    const { data } = await supabase
75	      .from("invoice_items")
76	      .select("*")
77	      .eq("invoice_id", invoice.id);
78	    if (data) {
79	      setItems(data.map((item) => ({
80	        id: item.id,
81	        description: item.description,
82	        quantity: Number(item.quantity),
83	        unit_price: Number(item.unit_price),
84	        total: Number(item.total),
85	      })));
86	    }
87	  };
88	
89	  const fetchProfile = async () => {
90	    const { data: { session } } = await supabase.auth.getSession();
91	    if (session) {
92	      const { data } = await supabase.from("profiles").select("*").eq("id", session.user.id).single();
93	      setProfile(data);
94	    }
95	  };
96	
97	  const fetchBusinessSettings = async () => {
98	    const { data: { session } } = await supabase.auth.getSession();
99	    if (session) {
100	      const { data } = await supabase.from("business_settings").select("*").eq("user_id", session.user.id).maybeSingle();
101	      setBusinessSettings(data);
102	    }
103	  };
104	
105	  const handleColorSelect = async (hex: string, isPro: boolean) => {
106	    if (isPro && !isProUser) {
107	      toast.error("Pro feature", { description: "Upgrade to Pro to unlock all invoice color themes." });
108	      return;
109	    }
110	    setAccentColor(hex);
111	    setShowPalette(false);
112	    setSavingColor(true);
113	    const { error } = await supabase
114	      .from("invoices")
115	      .update({ accent_color: hex } as any)
116	      .eq("id", invoice.id);
117	    if (error) toast.error("Couldn't save color", { description: error.message });
118	    setSavingColor(false);
119	  };
120	
121	  const formatCurrency = (amount: number) =>
122	    new Intl.NumberFormat("en-KE", {
123	      style: "currency",
124	      currency: invoice?.currency || "KES",
125	    }).format(amount);
126	
127	  if (!invoice) return null;
128	
129	  const statusConfig: Record<string, { bg: string; text: string; label: string; icon: React.ReactNode }> = {
130	    draft:     { bg: "bg-gray-100",    text: "text-gray-600",    label: "DRAFT",     icon: <Clock className="h-4 w-4" /> },
131	    sent:      { bg: "bg-blue-100",    text: "text-blue-700",    label: "SENT",      icon: <Send className="h-4 w-4" /> },
132	    paid:      { bg: "bg-emerald-100", text: "text-emerald-700", label: "PAID",      icon: <CheckCircle2 className="h-4 w-4" /> },
133	    overdue:   { bg: "bg-red-100",     text: "text-red-700",     label: "OVERDUE",   icon: <AlertCircle className="h-4 w-4" /> },
134	    cancelled: { bg: "bg-gray-100",    text: "text-gray-500",    label: "CANCELLED", icon: <Clock className="h-4 w-4" /> },
135	  };
136	  const status = statusConfig[invoice.status] || statusConfig.draft;
137	
138	  const hexToRgba = (hex: string, alpha: number) => {
139	    const r = parseInt(hex.slice(1, 3), 16);
140	    const g = parseInt(hex.slice(3, 5), 16);
141	    const b = parseInt(hex.slice(5, 7), 16);
142	    return `rgba(${r},${g},${b},${alpha})`;
143	  };
144	
145	  const currentTheme = INVOICE_THEMES.find((t) => t.hex === accentColor) || INVOICE_THEMES[0];
146	  const businessName = businessSettings?.business_name || profile?.display_name || profile?.handle || "Your Name";
147	
148	  return (
149	  <>
150	    <Dialog open={open} onOpenChange={(v) => { if (!v) { setIsFullscreen(false); setShowPalette(false); } onOpenChange(v); }}>
151	      {/* Hide shadcn's auto-generated close button — we have our own in the toolbar */}
152	      <DialogContent className={cn(
153	        "overflow-hidden p-0 transition-all duration-300 [&>button:last-child]:hidden",
154	        isFullscreen
155	          ? "max-w-[100vw] w-screen h-screen max-h-screen rounded-none"
156	          : "w-[calc(100vw-16px)] sm:max-w-2xl lg:max-w-3xl max-h-[95dvh] sm:max-h-[90vh]"
157	      )}>
158	
159	        {/* ── Toolbar ── */}
160	        <div className="sticky top-0 z-10 bg-background/95 backdrop-blur-sm border-b px-3 py-2 flex items-center gap-2">
161	          <DialogTitle className="font-vollkorn text-sm sm:text-base truncate min-w-0 flex-1">
162	            Invoice Preview
163	          </DialogTitle>
164	
165	          <div className="flex items-center gap-1 flex-shrink-0">
166	            {/* Theme picker */}
167	            <div className="relative">
168	              <Button
169	                variant="outline"
170	                size="sm"
171	                onClick={() => setShowPalette((v) => !v)}
172	                className="h-8 w-8 p-0"
173	                title="Color theme"
174	              >
175	                <span
176	                  className="w-3.5 h-3.5 rounded-full border border-border/40"
177	                  style={{ background: accentColor }}
178	                />
179	              </Button>
180	
181	              {showPalette && (
182	                <div className="absolute right-0 top-10 z-50 w-56 rounded-2xl bg-card border border-border shadow-2xl p-3 space-y-2.5">
183	                  <div className="flex items-center justify-between px-0.5">
184	                    <p className="text-xs font-semibold text-foreground">Invoice Theme</p>
185	                    {!isProUser && (
186	                      <span className="text-[10px] font-bold text-bronze bg-bronze/10 px-2 py-0.5 rounded-full uppercase tracking-wider">
187	                        Pro
188	                      </span>
189	                    )}
190	                  </div>
191	                  <div className="grid grid-cols-6 gap-2">
192	                    {INVOICE_THEMES.map((theme) => {
193	                      const locked = theme.pro && !isProUser;
194	                      const active = accentColor === theme.hex;
195	                      return (
196	                        <button
197	                          key={theme.hex}
198	                          title={theme.name}
199	                          onClick={() => handleColorSelect(theme.hex, theme.pro)}
200	                          className={cn(
201	                            "relative w-8 h-8 rounded-xl transition-all duration-150",
202	                            active ? "ring-2 ring-offset-2 ring-foreground scale-110" : "hover:scale-105",
203	                            locked ? "opacity-50 cursor-not-allowed" : "cursor-pointer"
204	                          )}
205	                          style={{ background: theme.hex }}
206	                        >
207	                          {locked && (
208	                            <span className="absolute inset-0 flex items-center justify-center">
209	                              <Lock className="w-3 h-3 text-white drop-shadow" />
210	                            </span>
211	                          )}
212	                          {active && !locked && (
213	                            <span className="absolute inset-0 flex items-center justify-center">
214	                              <CheckCircle2 className="w-3.5 h-3.5 text-white drop-shadow" />
215	                            </span>
216	                          )}
217	                        </button>
218	                      );
219	                    })}
220	                  </div>
221	                  {!isProUser && (
222	                    <p className="text-[11px] text-muted-foreground text-center pt-1 border-t border-border/50">
223	                      Upgrade to Pro to unlock all 12 themes
224	                    </p>
225	                  )}
226	                </div>
227	              )}
228	            </div>
229	
230	            <Button variant="outline" size="sm" onClick={() => setShowSendDialog(true)} className="h-8 w-8 p-0" title="Send">
231	              <Send className="h-3.5 w-3.5" />
232	            </Button>
233	            <Button variant="outline" size="sm" onClick={download} disabled={downloading} className="h-8 w-8 p-0" title="Download">
234	              <Download className="h-3.5 w-3.5" />
235	            </Button>
236	            <Button variant="outline" size="sm" onClick={() => window.print()} className="h-8 w-8 p-0 hidden sm:flex" title="Print">
237	              <Printer className="h-3.5 w-3.5" />
238	            </Button>
239	            <Button variant="outline" size="sm" onClick={() => setIsFullscreen(!isFullscreen)} className="h-8 w-8 p-0 hidden sm:flex" title={isFullscreen ? "Exit fullscreen" : "Fullscreen"}>
240	              {isFullscreen ? <Minimize2 className="h-3.5 w-3.5" /> : <Maximize2 className="h-3.5 w-3.5" />}
241	            </Button>
242	            <Button variant="ghost" size="sm" onClick={() => onOpenChange(false)} className="h-8 w-8 p-0" title="Close">
243	              <X className="h-4 w-4" />
244	            </Button>
245	          </div>
246	        </div>
247	
248	        {/* ── Invoice Document ── */}
249	        <div className="overflow-y-auto max-h-[calc(95dvh-52px)] sm:max-h-[calc(90vh-52px)]">
250	          <div className="p-3 sm:p-6">
251	            <div ref={docRef} className="bg-white text-black rounded-xl shadow-lg overflow-hidden print:shadow-none">
252	
253	              {/* Accent bar */}
254	              <div className="h-1.5" style={{ background: accentColor }} />
255	
256	              <div className="p-4 sm:p-8">
257	
258	                {/* ── Header: INVOICE + business info ── */}
259	                {/* Mobile: stacked; Desktop: side-by-side */}
260	                <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-3 mb-6">
261	                  <div>
262	                    <h1 className="text-2xl sm:text-3xl font-bold text-gray-900 tracking-tight">INVOICE</h1>
263	                    <p className="text-gray-400 mt-0.5 text-xs sm:text-base font-mono">{invoice.invoice_number}</p>
264	                  </div>
265	                  <div className="sm:text-right">
266	                    {businessSettings?.logo_url && (
267	                      <img
268	                        src={businessSettings.logo_url}
269	                        alt="Business Logo"
270	                        className="w-12 h-12 object-contain sm:ml-auto mb-1.5 rounded-lg"
271	                      />
272	                    )}
273	                    <h2 className="text-base font-bold text-gray-900">{businessName}</h2>
274	                    {(businessSettings?.business_email || profile?.email) && (
275	                      <p className="text-gray-500 text-xs mt-0.5 break-all">{businessSettings?.business_email || profile?.email}</p>
276	                    )}
277	                    {businessSettings?.business_phone && (
278	                      <p className="text-gray-500 text-xs">{businessSettings.business_phone}</p>
279	                    )}
280	                    {businessSettings?.business_address && (
281	                      <p className="text-gray-500 text-xs whitespace-pre-line mt-0.5">{businessSettings.business_address}</p>
282	                    )}
283	                  </div>
284	                </div>
285	
286	                {/* ── Bill To + Dates ── */}
287	                {/* Mobile: Bill To full width, then Issue/Due in 2-col */}
288	                <div className="mb-6">
289	                  <div className="mb-4">
290	                    <p className="text-[10px] uppercase tracking-widest mb-1 font-bold" style={{ color: accentColor }}>
291	                      Bill To
292	                    </p>
293	                    <p className="font-bold text-gray-900 text-sm sm:text-base">{invoice.client_name}</p>
294	                    {invoice.client_email && <p className="text-gray-500 text-xs mt-0.5 break-all">{invoice.client_email}</p>}
295	                    {invoice.client_address && <p className="text-gray-500 text-xs whitespace-pre-line mt-0.5">{invoice.client_address}</p>}
296	                  </div>
297	                  <div className="grid grid-cols-2 gap-3">
298	                    <div>
299	                      <p className="text-[10px] uppercase tracking-widest mb-1 font-bold" style={{ color: accentColor }}>
300	                        Issue Date
301	                      </p>
302	                      <p className="font-semibold text-gray-900 text-xs sm:text-sm">
303	                        {format(new Date(invoice.issue_date), "MMM d, yyyy")}
304	                      </p>
305	                    </div>
306	                    <div className="text-right">
307	                      <p className="text-[10px] uppercase tracking-widest mb-1 font-bold" style={{ color: accentColor }}>
308	                        Due Date
309	                      </p>
310	                      <p className="font-semibold text-gray-900 text-xs sm:text-sm">
311	                        {format(new Date(invoice.due_date), "MMM d, yyyy")}
312	                      </p>
313	                    </div>
314	                  </div>
315	                </div>
316	
317	                {/* ── Items ── */}
318	                {/* Mobile: card list. Desktop: table */}
319	                <div className="mb-6">
320	                  {/* Mobile card list */}
321	                  <div className="sm:hidden">
322	                    <div className="flex justify-between pb-2 mb-2" style={{ borderBottom: `2px solid ${accentColor}` }}>
323	                      <span className="text-[10px] uppercase tracking-wider font-bold" style={{ color: accentColor }}>Description</span>
324	                      <span className="text-[10px] uppercase tracking-wider font-bold" style={{ color: accentColor }}>Amount</span>
325	                    </div>
326	                    {items.map((item, idx) => (
327	                      <div
328	                        key={item.id}
329	                        className="py-3"
330	                        style={{ borderBottom: `1px solid ${idx === items.length - 1 ? "#e5e7eb" : "#f3f4f6"}` }}
331	                      >
332	                        <div className="flex justify-between items-start gap-2">
333	                          <p className="text-gray-900 font-medium text-sm flex-1 min-w-0">{item.description}</p>
334	                          <p className="text-gray-900 font-semibold text-sm flex-shrink-0">{formatCurrency(item.total)}</p>
335	                        </div>
336	                        <div className="flex items-center gap-2 mt-1">
337	                          <span className="text-gray-400 text-xs">{item.quantity} × {formatCurrency(item.unit_price)}</span>
338	                        </div>
339	                      </div>
340	                    ))}
341	                  </div>
342	
343	                  {/* Desktop table */}
344	                  <div className="hidden sm:block overflow-x-auto">
345	                    <table className="w-full">
346	                      <thead>
347	                        <tr style={{ borderBottom: `2px solid ${accentColor}` }}>
348	                          <th className="text-left py-3 text-xs uppercase tracking-wider font-bold" style={{ color: accentColor }}>Description</th>
349	                          <th className="text-center py-3 text-xs uppercase tracking-wider font-bold w-16" style={{ color: accentColor }}>Qty</th>
350	                          <th className="text-right py-3 text-xs uppercase tracking-wider font-bold w-28" style={{ color: accentColor }}>Rate</th>
351	                          <th className="text-right py-3 text-xs uppercase tracking-wider font-bold w-28" style={{ color: accentColor }}>Amount</th>
352	                        </tr>
353	                      </thead>
354	                      <tbody>
355	                        {items.map((item, idx) => (
356	                          <tr
357	                            key={item.id}
358	                            className={idx === items.length - 1 ? "border-b border-gray-200" : "border-b border-gray-100"}
359	                          >
360	                            <td className="py-3 text-gray-900 font-medium text-sm">{item.description}</td>
361	                            <td className="py-3 text-center text-gray-600 text-sm">{item.quantity}</td>
362	                            <td className="py-3 text-right text-gray-600 text-sm">{formatCurrency(item.unit_price)}</td>
363	                            <td className="py-3 text-right text-gray-900 font-semibold text-sm">{formatCurrency(item.total)}</td>
364	                          </tr>
365	                        ))}
366	                      </tbody>
367	                    </table>
368	                  </div>
369	                </div>
370	
371	                {/* ── Totals ── */}
372	                <div className="flex justify-end mb-6">
373	                  <div className="w-full sm:w-64 space-y-1.5">
374	                    <div className="flex justify-between text-gray-500 text-sm">
375	                      <span>Subtotal</span>
376	                      <span className="font-medium">{formatCurrency(Number(invoice.subtotal))}</span>
377	                    </div>
378	                    {Number(invoice.tax_rate) > 0 && (
379	                      <div className="flex justify-between text-gray-500 text-sm">
380	                        <span>Tax ({invoice.tax_rate}%)</span>
381	                        <span className="font-medium">{formatCurrency(Number(invoice.tax_amount))}</span>
382	                      </div>
383	                    )}
384	                    {Number(invoice.discount_amount) > 0 && (
385	                      <div className="flex justify-between text-emerald-600 text-sm">
386	                        <span>Discount</span>
387	                        <span className="font-medium">-{formatCurrency(Number(invoice.discount_amount))}</span>
388	                      </div>
389	                    )}
390	                    <div className="flex justify-between pt-2.5" style={{ borderTop: `2px solid ${accentColor}` }}>
391	                      <span className="text-base font-bold text-gray-900">Total Due</span>
392	                      <span className="text-base font-bold" style={{ color: accentColor }}>
393	                        {formatCurrency(Number(invoice.total))}
394	                      </span>
395	                    </div>
396	                  </div>
397	                </div>
398	
399	                {/* ── Status Stamp ── */}
400	                <div className="flex justify-center mb-6">
401	                  <div className={`inline-flex items-center gap-2 px-5 py-2 rounded-full ${status.bg} ${status.text} font-bold text-xs tracking-widest`}>
402	                    {status.icon}
403	                    {status.label}
404	                  </div>
405	                </div>
406	
407	                {/* ── Notes & Terms ── */}
408	                {(invoice.notes || invoice.terms) && (
409	                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 pt-4" style={{ borderTop: `1px solid ${hexToRgba(accentColor, 0.2)}` }}>
410	                    {invoice.notes && (
411	                      <div>
412	                        <p className="text-[10px] uppercase tracking-widest mb-1.5 font-bold" style={{ color: accentColor }}>Notes</p>
413	                        <p className="text-gray-600 text-xs whitespace-pre-line">{invoice.notes}</p>
414	                      </div>
415	                    )}
416	                    {invoice.terms && (
417	                      <div>
418	                        <p className="text-[10px] uppercase tracking-widest mb-1.5 font-bold" style={{ color: accentColor }}>Payment Terms</p>
419	                        <p className="text-gray-600 text-xs whitespace-pre-line">{invoice.terms}</p>
420	                      </div>
421	                    )}
422	                  </div>
423	                )}
424	
425	                {/* ── Footer ── */}
426	                <div className="mt-8 pt-3 text-center" style={{ borderTop: `1px solid ${hexToRgba(accentColor, 0.2)}` }}>
427	                  <p className="text-xs font-medium" style={{ color: accentColor }}>Thank you for your business!</p>
428	                  <p className="text-gray-300 text-[10px] mt-0.5">
429	                    Generated with Crevia Studio · {format(new Date(), "yyyy")}
430	                  </p>
431	                </div>
432	
433	                {/* ── Free Watermark ── */}
434	                {!isProUser && (
435	                  <div className="mt-4 -mx-8 -mb-8 px-6 py-2.5 bg-amber-50 border-t border-amber-200 text-center">
436	                    <p className="text-[11px] text-amber-700 font-medium">
437	                      Created with <strong>Crevia Free</strong> · Upgrade to Pro to remove this watermark
438	                    </p>
439	                  </div>
440	                )}
441	
442	              </div>
443	            </div>
444	          </div>
445	        </div>
446	
447	      </DialogContent>
448	    </Dialog>
449	
450	    {invoice && (
451	      <SendDocumentDialog
452	        open={showSendDialog}
453	        onOpenChange={setShowSendDialog}
454	        type="invoice"
455	        documentId={invoice.id}
456	        defaultEmail={invoice.client_email || ""}
457	        documentLabel={`Invoice ${invoice.invoice_number} · ${invoice.client_name}`}
458	        onSent={() => onOpenChange(false)}
459	      />
460	    )}
461	  </>
462	  );
463	};
464	
465	export default InvoicePreviewDialog;
466

1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { 
7	  Plus, 
8	  Search, 
9	  FileText, 
10	  Send, 
11	  Eye,
12	  MoreHorizontal,
13	  Edit,
14	  Trash2,
15	  CheckCircle2,
16	  Clock,
17	  AlertCircle,
18	  XCircle,
19	  Receipt,
20	  Copy,
21	  Filter,
22	  ArrowUpDown,
23	  TrendingUp,
24	  DollarSign,
25	  Sparkles,
26	} from "lucide-react";
27	import { toast } from "sonner";
28	import { format, isAfter } from "date-fns";
29	import {
30	  DropdownMenu,
31	  DropdownMenuContent,
32	  DropdownMenuItem,
33	  DropdownMenuSeparator,
34	  DropdownMenuTrigger,
