54	  const [loading, setLoading] = useState(false);
55	  const [editingId, setEditingId] = useState<string | null>(null);
56	  const [editForm, setEditForm] = useState(emptyForm);
57	  const [addingNew, setAddingNew] = useState(false);
58	  const [newForm, setNewForm] = useState(emptyForm);
59	  const [deleteTarget, setDeleteTarget] = useState<SavedClient | null>(null);
60	  const [saving, setSaving] = useState(false);
61	
62	  useEffect(() => {
63	    if (open) fetchClients();
64	  }, [open]);
65	
66	  const fetchClients = async () => {
67	    setLoading(true);
68	    try {
69	      const { data: { session } } = await supabase.auth.getSession();
70	      if (!session) return;
71	      const { data, error } = await (supabase as any)
72	        .from("saved_clients")
73	        .select("*")
74	        .eq("user_id", session.user.id)
75	        .order("client_name", { ascending: true });
76	      if (error) throw error;
77	      setClients(data || []);
78	    } catch (err: any) {
79	      toast.error(err.message || "Failed to load clients");
80	    } finally {
81	      setLoading(false);
82	    }
83	  };
84	
85	  const startEdit = (client: SavedClient) => {
86	    setEditingId(client.id);
87	    setEditForm({
88	      client_name: client.client_name,
89	      client_email: client.client_email || "",
90	      client_phone: client.client_phone || "",
91	      billing_address: client.billing_address || "",
92	      tax_id: client.tax_id || "",
93	    });
94	  };
95	
96	  const cancelEdit = () => {
97	    setEditingId(null);
98	    setEditForm(emptyForm);
99	  };
100	
101	  const saveEdit = async () => {
102	    if (!editForm.client_name.trim()) {
103	      toast.error("Client name is required");
104	      return;
105	    }
106	    setSaving(true);
107	    try {
108	      const { error } = await (supabase as any)
109	        .from("saved_clients")
110	        .update({
111	          client_name: editForm.client_name.trim(),
112	          client_email: editForm.client_email || null,
113	          client_phone: editForm.client_phone || null,
114	          billing_address: editForm.billing_address || null,
115	          tax_id: editForm.tax_id || null,
116	        })
117	        .eq("id", editingId);
118	      if (error) throw error;
119	      toast.success("Client updated");
120	      setEditingId(null);
121	      fetchClients();
122	    } catch (err: any) {
123	      toast.error(err.message || "Failed to update client");
124	    } finally {
125	      setSaving(false);
126	    }
127	  };
128	
129	  const confirmDelete = async () => {
130	    if (!deleteTarget) return;
131	    try {
132	      const { error } = await (supabase as any)
133	        .from("saved_clients")
134	        .delete()
135	        .eq("id", deleteTarget.id);
136	      if (error) throw error;
137	      toast.success(`${deleteTarget.client_name} removed`);
138	      setDeleteTarget(null);
139	      fetchClients();
140	    } catch (err: any) {
141	      toast.error(err.message || "Failed to delete client");
142	    }
143	  };
144	
145	  const saveNew = async () => {
146	    if (!newForm.client_name.trim()) {
147	      toast.error("Client name is required");
148	      return;
149	    }
150	    setSaving(true);
151	    try {
152	      const { data: { session } } = await supabase.auth.getSession();
153	      if (!session) return;
154	      const { error } = await (supabase as any)
155	        .from("saved_clients")
156	        .insert({
157	          user_id: session.user.id,
158	          client_name: newForm.client_name.trim(),
159	          client_email: newForm.client_email || null,
160	          client_phone: newForm.client_phone || null,
161	          billing_address: newForm.billing_address || null,
162	          tax_id: newForm.tax_id || null,
163	        });
164	      if (error) throw error;
165	      toast.success("Client saved");
166	      setAddingNew(false);
167	      setNewForm(emptyForm);
168	      fetchClients();
169	    } catch (err: any) {
170	      toast.error(err.message || "Failed to save client");
171	    } finally {
172	      setSaving(false);
173	    }
174	  };
175	
176	  return (
177	    <>
178	      <Sheet open={open} onOpenChange={onOpenChange}>
179	        <SheetContent className="w-full sm:max-w-lg overflow-y-auto flex flex-col gap-0 p-0">
180	          <SheetHeader className="px-6 py-5 border-b border-border sticky top-0 bg-background z-10">
181	            <SheetTitle className="flex items-center gap-2 font-vollkorn text-lg">
182	              <Users className="h-5 w-5 text-bronze" />
183	              Client Address Book
184	              {clients.length > 0 && (
185	                <Badge variant="secondary" className="ml-1 text-xs font-normal">
186	                  {clients.length}
187	                </Badge>
188	              )}
189	            </SheetTitle>
190	          </SheetHeader>
191	
192	          <div className="flex-1 px-6 py-5 space-y-4">
193	            {/* Add New Client */}
194	            {!addingNew ? (
195	              <Button
196	                variant="outline"
197	                size="sm"
198	                className="w-full gap-2 border-dashed border-bronze/40 text-bronze hover:bg-bronze/5"
199	                onClick={() => setAddingNew(true)}
200	              >
201	                <Plus className="h-4 w-4" />
202	                Add New Client
203	              </Button>
204	            ) : (
205	              <ClientForm
206	                form={newForm}
207	                onChange={setNewForm}
208	                onSave={saveNew}
209	                onCancel={() => { setAddingNew(false); setNewForm(emptyForm); }}
210	                saving={saving}
211	                title="New Client"
212	              />
213	            )}
214	
215	            {/* Client List */}
216	            {loading ? (
217	              <div className="space-y-3">
218	                {[1, 2, 3].map(i => (
219	                  <div key={i} className="h-24 rounded-xl bg-muted/40 animate-pulse" />
220	                ))}
221	              </div>
222	            ) : clients.length === 0 ? (
223	              <div className="flex flex-col items-center justify-center py-12 text-center">
224	                <Users className="h-10 w-10 text-muted-foreground/30 mb-3" />
225	                <p className="text-sm font-medium text-muted-foreground">No saved clients yet</p>
226	                <p className="text-xs text-muted-foreground/60 mt-1">
227	                  Clients you save while creating invoices appear here.
228	                </p>
229	              </div>
230	            ) : (
231	              <div className="space-y-3">
232	                {clients.map(client => (
233	                  <div
234	                    key={client.id}
235	                    className="rounded-xl border border-border bg-muted/20 overflow-hidden"
236	                  >
237	                    {editingId === client.id ? (
238	                      <div className="p-4">
239	                        <ClientForm
240	                          form={editForm}
241	                          onChange={setEditForm}
242	                          onSave={saveEdit}
243	                          onCancel={cancelEdit}
244	                          saving={saving}
245	                          title="Edit Client"
246	                        />
247	                      </div>
248	                    ) : (
249	                      <div className="p-4">
250	                        <div className="flex items-start justify-between gap-2">
251	                          <div className="flex-1 min-w-0 space-y-1">
252	                            <p className="font-semibold text-sm text-foreground truncate">
253	                              {client.client_name}
254	                            </p>
255	                            {client.client_email && (
256	                              <p className="flex items-center gap-1.5 text-xs text-muted-foreground truncate">
257	                                <Mail className="h-3 w-3 flex-shrink-0" />
258	                                {client.client_email}
259	                              </p>
260	                            )}
261	                            {client.client_phone && (
262	                              <p className="flex items-center gap-1.5 text-xs text-muted-foreground">
263	                                <Phone className="h-3 w-3 flex-shrink-0" />
264	                                {client.client_phone}
265	                              </p>
266	                            )}
267	                            {client.billing_address && (
268	                              <p className="flex items-start gap-1.5 text-xs text-muted-foreground">
269	                                <MapPin className="h-3 w-3 flex-shrink-0 mt-0.5" />
270	                                <span className="whitespace-pre-line">{client.billing_address}</span>
271	                              </p>
272	                            )}
273	                            {client.tax_id && (
274	                              <p className="flex items-center gap-1.5 text-xs text-muted-foreground">
275	                                <Hash className="h-3 w-3 flex-shrink-0" />
276	                                Tax ID: {client.tax_id}
277	                              </p>
278	                            )}
279	                          </div>
280	                          <div className="flex items-center gap-1 flex-shrink-0">
281	                            <Button
282	                              variant="ghost"
283	                              size="icon"
284	                              className="h-7 w-7 text-muted-foreground hover:text-foreground"
285	                              onClick={() => startEdit(client)}
286	                            >
287	                              <Pencil className="h-3.5 w-3.5" />
288	                            </Button>
289	                            <Button
290	                              variant="ghost"
291	                              size="icon"
292	                              className="h-7 w-7 text-muted-foreground hover:text-destructive"
293	                              onClick={() => setDeleteTarget(client)}
294	                            >
295	                              <Trash2 className="h-3.5 w-3.5" />
296	                            </Button>
297	                          </div>
298	                        </div>
299	                      </div>
300	                    )}
301	                  </div>
302	                ))}
303	              </div>
304	            )}
305	          </div>
306	        </SheetContent>
307	      </Sheet>
308	
309	      <AlertDialog open={!!deleteTarget} onOpenChange={open => !open && setDeleteTarget(null)}>
310	        <AlertDialogContent>
311	          <AlertDialogHeader>
312	            <AlertDialogTitle>Remove Client</AlertDialogTitle>
313	            <AlertDialogDescription>
314	              Remove <strong>{deleteTarget?.client_name}</strong> from your address book? This does not affect any existing invoices.
315	            </AlertDialogDescription>
316	          </AlertDialogHeader>
317	          <AlertDialogFooter>
318	            <AlertDialogCancel>Cancel</AlertDialogCancel>
319	            <AlertDialogAction
320	              className="bg-destructive hover:bg-destructive/90"
321	              onClick={confirmDelete}
322	            >
323	              Remove
324	            </AlertDialogAction>
325	          </AlertDialogFooter>
326	        </AlertDialogContent>
327	      </AlertDialog>
328	    </>
329	  );
330	}
