332	interface ClientFormProps {
333	  form: typeof emptyForm;
334	  onChange: (form: typeof emptyForm) => void;
335	  onSave: () => void;
336	  onCancel: () => void;
337	  saving: boolean;
338	  title: string;
339	}
340	
341	function ClientForm({ form, onChange, onSave, onCancel, saving, title }: ClientFormProps) {
342	  const set = (field: keyof typeof emptyForm) => (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) =>
343	    onChange({ ...form, [field]: e.target.value });
344	
345	  return (
346	    <div className="space-y-3">
347	      <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">{title}</p>
348	      <div className="grid grid-cols-1 gap-2.5">
349	        <div>
350	          <Label className="text-xs">Name *</Label>
351	          <Input value={form.client_name} onChange={set("client_name")} placeholder="Company or individual" className="mt-1 h-8 text-sm" />
352	        </div>
353	        <div className="grid grid-cols-2 gap-2">
354	          <div>
355	            <Label className="text-xs">Email</Label>
356	            <Input type="email" value={form.client_email} onChange={set("client_email")} placeholder="client@co.com" className="mt-1 h-8 text-sm" />
357	          </div>
358	          <div>
359	            <Label className="text-xs">Phone</Label>
360	            <Input value={form.client_phone} onChange={set("client_phone")} placeholder="+254 700 000 000" className="mt-1 h-8 text-sm" />
361	          </div>
362	        </div>
363	        <div>
364	          <Label className="text-xs">Billing Address</Label>
365	          <Textarea value={form.billing_address} onChange={set("billing_address")} placeholder="Full address" className="mt-1 text-sm" rows={2} />
366	        </div>
367	        <div>
368	          <Label className="text-xs">Tax ID / KRA PIN</Label>
369	          <Input value={form.tax_id} onChange={set("tax_id")} placeholder="Optional" className="mt-1 h-8 text-sm" />
370	        </div>
371	      </div>
372	      <div className="flex gap-2 pt-1">
373	        <Button size="sm" onClick={onSave} disabled={saving} className="bg-bronze hover:bg-bronze/90 gap-1.5">
374	          <Check className="h-3.5 w-3.5" />
375	          {saving ? "Saving..." : "Save"}
376	        </Button>
377	        <Button size="sm" variant="ghost" onClick={onCancel} className="gap-1.5">
378	          <X className="h-3.5 w-3.5" />
379	          Cancel
380	        </Button>
381	      </div>
382	    </div>
383	  );
384	}
